class PostAdapter : ListAdapter<Post, PostVH>(PostDiff()) {
    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): PostVH {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_post, parent, false)
        return PostVH(view)
    }

    override fun onBindViewHolder(holder: PostVH, position: Int) {
        val post = getItem(position)
        holder.title.text = post.title
        Glide.with(holder.image).load(post.imageUrl).into(holder.image)
        holder.likeCount.text = "${post.likes} likes"
    }

    override fun onBindViewHolder(holder: PostVH, position: Int, payloads: MutableList<Any>) {
        if (payloads.isEmpty()) {
            onBindViewHolder(holder, position)
            return
        }
        val changes = payloads[0] as Set<*>
        val post = getItem(position)
        if ("likes" in changes) holder.likeCount.text = "${post.likes} likes"
        if ("title" in changes) holder.title.text = post.title
        if ("image" in changes) Glide.with(holder.image).load(post.imageUrl).into(holder.image)
    }
}

class PostDiff : DiffUtil.ItemCallback<Post>() {
    override fun areItemsTheSame(old: Post, new: Post) = old.id == new.id
    override fun areContentsTheSame(old: Post, new: Post) = old == new

    override fun getChangePayload(old: Post, new: Post): Any? {
        val changes = mutableSetOf<String>()
        if (old.likes != new.likes) changes.add("likes")
        if (old.title != new.title) changes.add("title")
        if (old.imageUrl != new.imageUrl) changes.add("image")
        return changes.ifEmpty { null }
    }
}
